-- ----------------------------
-- Table structure for weather_data
-- ----------------------------
DROP TABLE IF EXISTS `weather_data`;
CREATE TABLE `weather_data`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `time` datetime NOT NULL COMMENT '数据时间点',
  `city_no` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '地市编码',
  `city_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '地市名称',
  `load_mw` decimal(10, 2) NULL DEFAULT NULL COMMENT '电力负荷(MW)',
  `temp` decimal(5, 1) NULL DEFAULT NULL COMMENT '温度(℃)',
  `humidity` int(11) NULL DEFAULT NULL COMMENT '相对湿度(%)',
  `weather_code` tinyint(4) NULL DEFAULT NULL COMMENT '天气编码 0晴1多云2阴3小雨4中雨5霾6浮尘',
  `is_rain` tinyint(4) NULL DEFAULT NULL COMMENT '是否降雨 0否1是',
  `hour` tinyint(4) NULL DEFAULT NULL COMMENT '小时 0-23',
  `day_of_week` tinyint(4) NULL DEFAULT NULL COMMENT '星期1-7',
  `is_holiday` tinyint(4) NULL DEFAULT NULL COMMENT '是否节假日 0否1是',
  `shortwave_radiation` decimal(8, 2) NULL DEFAULT NULL COMMENT '总短波辐射(W/m²)',
  `direct_radiation` decimal(8, 2) NULL DEFAULT NULL COMMENT '直接辐射(W/m²)',
  `diffuse_radiation` decimal(8, 2) NULL DEFAULT NULL COMMENT '散射辐射(W/m²)',
  `sunshine_duration` int(11) NULL DEFAULT NULL COMMENT '日照时长(秒/小时)',
  `wind_level` tinyint(4) NULL DEFAULT NULL COMMENT '风力等级(0-12级)',
  `wind_direction` decimal(6, 2) NULL DEFAULT NULL COMMENT '风向(°)',
  `wind_gusts` decimal(5, 1) NULL DEFAULT NULL COMMENT '阵风风速(m/s)',
  `wind_speed` decimal(4, 1) NULL DEFAULT NULL COMMENT '风速(km/h)',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_time_city_no`(`time`, `city_no`) USING BTREE,
  INDEX `idx_city_time`(`city_no`, `time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7331 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '气温数据小时级' ROW_FORMAT = Dynamic;

